func (r *mutationResolver) PersonaFork(ctx context.Context, libraryName string, newName *string, projectID string) (*Persona, error) {
	writer := persona.NewProjectPersonaWriter(r.projectRoot(ctx, projectID))
	target := ""
	if newName != nil {
		target = *newName
	}
